declare(strict_types=1);

namespace Factuarea\Sdk\Custom\Webhooks;

/**
 * Thrown when a webhook signature cannot be verified.
 *
 * Reasons include a missing or malformed `Factuarea-Signature` header, a
 * timestamp outside the allowed tolerance (replay protection), or a payload
 * whose HMAC does not match any of the signatures advertised by the header.
 *
 * The exception message never contains the signing secret.
 */
final class WebhookSignatureException extends \RuntimeException
{
    public static function missingHeader(): self
    {
        return new self('Missing or empty Factuarea-Signature header.');
    }

    public static function malformedHeader(): self
    {
        return new self('Malformed Factuarea-Signature header: expected "t=<timestamp>,v1=<hex>".');
    }

    public static function timestampTooOld(int $toleranceSeconds): self
    {
        return new self(sprintf(
            'Webhook timestamp is outside the allowed tolerance of %d seconds (possible replay).',
            $toleranceSeconds,
        ));
    }

    public static function noMatchingSignature(): self
    {
        return new self('No signature in the Factuarea-Signature header matches the computed HMAC.');
    }
}
